import Vue from 'vue'
import VueRouter from 'vue-router'
// import Home from '../views/Home.vue'
import login from '../views/login1.vue'

Vue.use(VueRouter)

// 解决ElementUI导航栏中的vue-router在3.0版本以上重复点菜单报错问题
const originalPush = VueRouter.prototype.push
VueRouter.prototype.push = function push(location) {
  return originalPush.call(this, location).catch(err => err)
}

const routes = [
  {
    path: '/login',
    name: 'login',
    component: login
  },
  {
    path: '/',
    redirect: '/index'
  },
  {
    path: '/about',
    name: 'About',
    component: function () {
      return import('../views/About.vue')
    }
  },
  {
    path: '/index',
    name: 'index',
    component: function () {
      return import('../views/index1.vue')
    },
    beforeEnter: (to, from, next) => {
      let a = sessionStorage.getItem('token')
      if (a) {
        next()
      } else {
        alert('请先登录')
        next('/login')
      }
    },
    children: [
      {
        path: 'welcome',
        name: 'welcome',
        component: function () {
          return import('../components/welcome.vue')
        }
      },
      {
        path: 'lie',
        name: 'lie',
        component: function () {
          return import('../components/lie1.vue')
        }
      },
      {
        path: 'users',
        name: 'users',
        component: function () {
          return import('../components/users.vue')
        }
      },
      {
        path: 'roles',
        name: 'roles',
        component: function () {
          return import('../components/roles.vue')
        }
      },
      {
        path: 'rights',
        name: 'rights',
        component: function () {
          return import('../components/rights.vue')
        }
      },
      {
        path: 'goods',
        name: 'goods',
        component: function () {
          return import('../components/goods.vue')
        }
      },
      {
        path: 'orders',
        name: 'orders',
        component: function () {
          return import('../components/orders.vue')
        }
      },
      {
        path: 'params',
        name: 'params',
        component: function () {
          return import('../components/params.vue')
        }
      },
      {
        path: 'categories',
        name: 'categories',
        component: function () {
          return import('../components/categories.vue')
        }
      },
      {
        path: 'reports',
        name: 'reports',
        component: function () {
          return import('../components/reports.vue')
        }
      },
      {
        path:'/index',
        redirect: '/index/welcome'
      }
    ]
  }
]

const router = new VueRouter({
  routes
})

export default router
