<template>
    <div>
      <div class="login-box">
         <div class="avatar-box">
               <img src="../assets/222.jpg" alt="">
         </div>

         <el-form :model="ruleForm" :rules="rules" ref="ruleForm"  class="demo-ruleForm">
            <el-form-item  prop="username">
              <el-input prefix-icon="el-icon-user-solid" v-model="ruleForm.username"></el-input>
            </el-form-item>
            <el-form-item  prop="password">
               <el-input type="password" prefix-icon="el-icon-lock" v-model="ruleForm.password"></el-input>
             </el-form-item>
             <el-form-item class="btn-box">
               <el-button type="primary" @click="submitForm('ruleForm')">登录</el-button>
               <el-button @click="resetForm('ruleForm')">重置</el-button>
             </el-form-item>
         </el-form>
      </div>
    </div>
</template>

<script>
export default {
    data() {
        return {
         ruleForm: {
          username: 'admin',
          password:'123456'
        },
        rules: {
          username: [
            { required: true, message: '请输入用户名', trigger: 'blur' },
            { min: 3, max: 16, message: '长度在 3 到 16 个字符', trigger: 'blur' }
          ],
          password: [
            { required: true, message: '请输入密码', trigger: 'blur' },
            { min: 3, max: 16, message: '长度在 3 到 16 个字符', trigger: 'blur' }
          ],

        }
        };
    },
    created() {

    },
    mounted() {

    },
    methods: {
      submitForm(formName) {
        this.$refs[formName].validate((valid) => {
          if (valid) {
            // alert('submit!');
            // 点击成功就调用这个方法
            this.ajax()
          } else {
            console.log('error submit!!');
            return false;
          }
        });
      },
      resetForm(formName) {
        this.$refs[formName].resetFields();
      },
      async ajax(){
         let { data } = await this.$http.post('/login', this.ruleForm)
            // console.log(data)
            // 如果成功，就弹出成功
            if(data.meta.status==200){
               sessionStorage.setItem('token',data.data.token)
               this.$router.push('/index')
               this.$message({
                  message:data.meta.msg,
                  type:'success',
                  duration:1000
               })
            }else{
               // 失败就弹出失败
               this.$message({
                  message:data.meta.msg,
                  type:'error',
                  duration:2000
               })
            }
      }
    }
};
</script>

<style scoped>
.login-box{
   background-color: #fff;
    position: absolute;
    left: 50%;
    transform: translate(-50%,-50%);
    box-shadow: 0 0 10px #ddd;
    width: 450px;
    height: 304px;
    border-radius: 3px;
    top: 50%;
}
.avatar-box{
   width: 130px;
    height: 130px;
    padding: 10px;
    border: 1px solid #efefef;
    border-radius: 50%;
    background-color: #fff;
    position: absolute;
    left: 50%;
    transform: translate(-50%,-50%);
    box-shadow: 0 0 10px #ddd;
}
.avatar-box>img{
   width: 100%;
    height: 100%;
    border-radius: 50%;
    background-color: #efefef;
}
.el-form{
   position: absolute;
    bottom: 0;
    left: 0;
    width: 100%;
    padding: 0 20px;
    box-sizing: border-box;
}
.btn-box{
   display: flex;
    justify-content: flex-end;
}
</style>
